def get_quadratic_roots(a: float, b: float, c: float) -> Optional[Tuple[float, float]]:
    discriminant = b**2 - 4*a*c
    if discriminant < 0:
        return None
    sqrt_d = discriminant**0.5
    return (-b + sqrt_d) / (2*a), (-b - sqrt_d) / (2*a)

